module Campbooks
  # Inline SVG icon rendered by name from one curated, app-wide set. The folder
  # chips, the icon picker, and (later) the folder pane all draw from this single
  # source so a folder's chosen icon looks identical everywhere it appears.
  #
  # Icons are Heroicons-style 24×24 outline paths: the <svg> root carries the
  # stroke/fill/width presentation attributes and each entry is just the inner
  # path markup (which inherits them). Unknown names fall back to :folder, so a
  # stored icon that's later removed from the set still renders something sane.
  #
  #   render(Campbooks::Icon.new("briefcase", css_class: "w-4 h-4"))
