    NAMES = PATHS.keys.freeze
    DEFAULT = "folder"

    # Provider/system folder name (case-insensitive) => glyph. These folders
    # aren't user-configurable, so their icon is derived from the name. Unknown
    # names fall back to the default folder glyph.
    SYSTEM_FOLDER_ICONS = {
      "inbox" => "inbox", "sent" => "paper-airplane", "drafts" => "pencil",
      "archive" => "archive", "spam" => "no-symbol", "trash" => "trash",
      "snoozed" => "clock", "starred" => "star", "outbox" => "paper-airplane",
      "templates" => "document", "newsletter" => "inbox", "notification" => "bell"
    }.freeze

    # The glyph name for a system/provider folder (e.g. "Inbox" → "inbox").
    def self.for_folder_name(name)
      SYSTEM_FOLDER_ICONS[name.to_s.strip.downcase] || DEFAULT
    end

    # @param name [String, Symbol] an entry in PATHS (unknown → DEFAULT)
    # @param css_class [String] Tailwind sizing/colour classes for the <svg>
    def initialize(name, css_class: "w-5 h-5")
      @name = NAMES.include?(name.to_s) ? name.to_s : DEFAULT
      @css_class = css_class
    end

    def view_template
      raw safe(
        %(<svg class="#{@css_class}" viewBox="0 0 24 24" fill="none" stroke="currentColor" ) +
        %(stroke-width="1.5" stroke-linecap="round" stroke-linejoin="round" aria-hidden="true">) +
        PATHS[@name] +
        "</svg>"
      )
    end
  end
